import type { CookieOptions } from 'express';

import { config } from 'frontend-config';
import { getReq, getRes } from '@meli/server-context';

export function concatCookieValue(key: string, value: string | undefined) {
  return value ? `${key}=${value},` : '';
}

export function setCookie(cookieName: string, cookieValue: string) {
  if (!cookieValue) {
    return;
  }

  const { cookies, platform } = getReq();
  const currentCookieValue = cookies[cookieName];

  if (currentCookieValue !== cookieValue) {
    const cookieOptions: CookieOptions = {
      httpOnly: true,
      secure: true,
      sameSite: false,
    };

    if (platform) {
      cookieOptions.domain = config.get(
        'url.mainDomain.link',
        platform.id,
        platform.siteId,
      );
    }

    getRes().cookie(cookieName, cookieValue, cookieOptions);
  }
}
